#include <stdio.h>
#include <string.h>

void generate(char *str, int len, int idx, int *encrypted, char *result) {
    if (idx == len) {
        int temp[8];
        for (int i = 0; i < len; i++) {
            temp[i] = 0;
            for (int j = 0; j < len; j++) {
                if (str[i] > str[j]) {
                    temp[i]++;
                }
            }
            temp[i] = (temp[i] + str[i] - 'a') % 10;
        }
        int match = 1;
        for (int i = 0; i < len; i++) {
            if (temp[i] != encrypted[i]) {
                match = 0;
                break;
            }
        }
        if (match) {
            strcpy(result, str);
        }
    } else {
        for (char c = 'a'; c <= 'z'; c++) {
            int valid = 1;
            for (int i = 0; i < idx; i++) {
                if (str[i] == c) {
                    valid = 0;
                    break;
                }
            }
            if (valid) {
                str[idx] = c;
                generate(str, len, idx + 1, encrypted, result);
            }
        }
    }
}

int main() {
    int T, N;
    scanf("%d %d", &T, &N);
    while (T--) {
        int encrypted[8];
        for (int i = 0; i < N; i++) {
            scanf("%1d", &encrypted[i]);
        }
        char str[8];
        char result[8];
        result[0] = '\0';
        generate(str, N, 0, encrypted, result);
        if (result[0] == '\0') {
            printf("-1\n");
        } else {
            printf("%s\n", result);
        }
    }
    return 0;
}

