                        temp[i]++;
                    }
                }
                temp[i] = (temp[i] + str[i] - 'a') % 10;
            }
            int match = 1;
            for (int i = 0; i < len; i++) {
                if (temp[i] != encrypted[i]) {
                    match = 0;
                    break;
                }
            }
            if (match) {
                result.append(new String(str));
            }
        } else {
            for (char c = 'a'; c <= 'z'; c++) {
                int valid = 1;
                for (int i = 0; i < idx; i++) {
                    if (str[i] == c) {
