def generate(str, len, idx, encrypted, result):
    if idx == len:
        temp = [0] * 8
        for i in range(len):
            for j in range(len):
                if str[i] > str[j]:
                    temp[i] += 1
            temp[i] = (temp[i] + ord(str[i]) - ord('a')) % 10
        match = 1
        for i in range(len):
            if temp[i] != encrypted[i]:
                match = 0
                break
        if match:
            result[0] = ''.join(str)
    else:
        for c in range(ord('a'), ord('z') + 1):
            valid = 1
            for i in range(idx):
                if str[i] == chr(c):
                    valid = 0
                    break
            if valid:
                str[idx] = chr(c)
                generate(str, len, idx + 1, encrypted, result)

